import pytest
from pydantic import ValidationError

class TestInputValidation:
    @pytest.mark.parametrize("email", [
        "not-an-email",
        "@nodomain.com",
        "spaces in@email.com",
        "a" * 256 + "@example.com",
    ])
    def test_invalid_email_rejected(self, email):
        with pytest.raises(ValidationError):
            UserCreate(email=email, password="ValidPass1")

    @pytest.mark.parametrize("password", [
        "short",           # too short
        "nouppercase1",    # no uppercase
        "NOLOWERCASE1",    # no lowercase
        "NoDigitsHere",    # no digits
    ])
    def test_weak_password_rejected(self, password):
        with pytest.raises(ValidationError):
            UserCreate(email="valid@example.com", password=password)

    def test_file_upload_type_blocked(self, client, auth_token):
        response = client.post(
            "/api/upload",
            files={"file": ("malware.exe", b"MZ...", "application/x-msdownload")},
            headers={"Authorization": f"Bearer {auth_token}"}
        )
        assert response.status_code == 400

    def test_file_upload_size_limit(self, client, auth_token):
        large = b"x" * (10 * 1024 * 1024 + 1)  # > 10 MB
        response = client.post(
            "/api/upload",
            files={"file": ("large.txt", large, "text/plain")},
            headers={"Authorization": f"Bearer {auth_token}"}
        )
        assert response.status_code == 413

    @pytest.mark.parametrize("path", [
        "../../../etc/passwd",
        "....//....//....//etc/passwd",
        "%2e%2e%2f%2e%2e%2fetc/passwd",
    ])
    def test_path_traversal_blocked(self, client, auth_token, path):
        response = client.get(
            f"/api/files/{path}",
            headers={"Authorization": f"Bearer {auth_token}"}
        )
        assert response.status_code in [400, 404]
